   * Add an assignment for an existing receipt user to a line item.
   */
  const addExistingPersonAssignment = async (
    itemId: string,
    receiptUserId: string
  ) => {
    if (!receipt) {
      return;
    }

    const lineItem = receipt.lineItems.find((item) => item.id === itemId);
